# ROBUSTNESS PHASE H — Protocol precision: timing bytes, multi-DID batching,
#                      DTC record format, routine lifecycle completeness
# Manually written, not generated by testgen.py. Do not delete.
#
# Covers territory not reached by Phases A–G:
#   TestDSCTimingPrecision      — P2/P2* byte values must be numerically exact
#   TestMultiDIDReadByIdentifier — batch RDBI (multiple DIDs per request)
#   TestReadDTCPrecision        — sub 0x01/0x02 format, record layout, mask bits
#   TestRoutineControlLifecycle — stop-unsupported, security-gated, programming session
#
# Run: pytest test_robustness_H_protocol_precision.py -v
from __future__ import annotations

import os
import sys

import pytest

sys.path.insert(0, os.path.dirname(__file__))
from conftest import (
    _inline_handle,
    _InlineEcuState,
    _EcuSimulator,
    SID_DIAGNOSTIC_SESSION_CONTROL,
    SID_ECU_RESET,
    SID_READ_DATA_BY_ID,
    SID_WRITE_DATA_BY_ID,
    SID_SECURITY_ACCESS,
    SID_ROUTINE_CONTROL,
    SID_READ_DTC_INFO,
    SID_NEGATIVE_RESPONSE,
    SESSION_DEFAULT,
    SESSION_PROGRAMMING,
    SESSION_EXTENDED,
    NRC_INCORRECT_MSG_LEN,
    NRC_CONDITIONS_NOT_CORRECT,
    NRC_REQUEST_OUT_OF_RANGE,
    NRC_SECURITY_ACCESS_DENIED,
    NRC_SUB_FUNCTION_NOT_SUPPORTED,
    ALGO_SEED_LEN,
    ALGO_KEY_LEN,
    _LEVEL_KEYS,
    P2_SERVER_MAX_MS,
    P2_STAR_SERVER_MAX_MS,
)

NRC_SERVICE_NOT_SUPPORTED_IN_SESSION = 0x7F

# basic_ecu DIDs
DID_VIN        = 0xF190   # 17 bytes, read-only, min_session=default
DID_SERIAL     = 0xF18C   # 4 bytes,  read-only, min_session=default
DID_SPARE_PART = 0xF187   # 11 bytes, read+write, min_session=extended, write_sec=1
DID_ENGINE_SPD = 0x0C00   # 2 bytes,  read-only, min_session=default
DID_COOLANT    = 0x0500   # 1 byte,   read-only, min_session=default

# basic_ecu routines
RID_SELFTEST   = 0xFF00   # extended, sec=0, support=[start, results]
RID_FACTORY    = 0xFF01   # extended, sec=1, support=[start]
RID_ERASE_NVM  = 0xFF10   # programming, sec=1, support=[start, results]


def _sim():
    return _InlineEcuState()


def _req(state, pdu):
    return _inline_handle(pdu, state, False)


def _session(state, s):
    _inline_handle(bytes([SID_DIAGNOSTIC_SESSION_CONTROL, s]), state, False)


def _do_cmac_unlock(state, level=1):
    sub_seed = 2 * level - 1
    sub_key  = 2 * level
    resp = _req(state, bytes([SID_SECURITY_ACCESS, sub_seed]))
    if resp is None or resp[0] == SID_NEGATIVE_RESPONSE:
        return False
    seed = bytes(resp[2:])
    key_material = _LEVEL_KEYS.get(level, _LEVEL_KEYS[1])
    key = _EcuSimulator._cmac(key_material, seed)[:ALGO_KEY_LEN]
    resp2 = _req(state, bytes([SID_SECURITY_ACCESS, sub_key]) + key)
    return resp2 is not None and resp2[0] != SID_NEGATIVE_RESPONSE


def _rdbi(state, *dids):
    pdu = bytes([SID_READ_DATA_BY_ID])
    for did in dids:
        pdu += bytes([did >> 8, did & 0xFF])
    return _req(state, pdu)


# ===========================================================================
# TestDSCTimingPrecision
# ===========================================================================

class TestDSCTimingPrecision:
    """
    DSC positive response (0x50) carries 6 bytes:
      [0x50, sub, p2_hi, p2_lo, p2s_hi, p2s_lo]
    Bytes 2-5 must encode the exact millisecond values from the YAML timing block.
    """

    def test_dsc_p2_value_matches_config(self):
        s = _sim()
        resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_EXTENDED]))
        assert resp is not None and resp[0] == 0x50
        p2_ms = (resp[2] << 8) | resp[3]
        assert p2_ms == P2_SERVER_MAX_MS, \
            f"P2 encoded as {p2_ms}ms, expected {P2_SERVER_MAX_MS}ms"

    def test_dsc_p2star_value_matches_config(self):
        s = _sim()
        resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_EXTENDED]))
        assert resp is not None and resp[0] == 0x50
        p2s_ms = (resp[4] << 8) | resp[5]
        assert p2s_ms == P2_STAR_SERVER_MAX_MS, \
            f"P2* encoded as {p2s_ms}ms, expected {P2_STAR_SERVER_MAX_MS}ms"

    def test_dsc_p2_bytes_are_big_endian(self):
        s = _sim()
        resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_DEFAULT]))
        assert resp[2] == (P2_SERVER_MAX_MS >> 8) & 0xFF
        assert resp[3] == P2_SERVER_MAX_MS & 0xFF

    def test_dsc_p2star_bytes_are_big_endian(self):
        s = _sim()
        resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_DEFAULT]))
        assert resp[4] == (P2_STAR_SERVER_MAX_MS >> 8) & 0xFF
        assert resp[5] == P2_STAR_SERVER_MAX_MS & 0xFF

    def test_all_three_sessions_return_same_timing(self):
        """P2/P2* bytes are ECU constants — must be identical regardless of target session."""
        timing_sets = set()
        for session in (SESSION_DEFAULT, SESSION_EXTENDED, SESSION_PROGRAMMING):
            s = _sim()
            resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, session]))
            assert resp is not None and resp[0] == 0x50
            timing_sets.add(bytes(resp[2:6]))
        assert len(timing_sets) == 1, \
            "P2/P2* bytes must be identical for all three sessions"

    def test_dsc_sub_function_echoed_in_response(self):
        for session in (SESSION_DEFAULT, SESSION_EXTENDED, SESSION_PROGRAMMING):
            s = _sim()
            resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, session]))
            assert resp is not None and resp[1] == session, \
                f"Session 0x{session:02X}: sub-fn echo byte mismatch"

    def test_session_re_entry_returns_valid_dsc(self):
        """Entering the same session again (default→default) must succeed."""
        s = _sim()
        resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_DEFAULT]))
        assert resp is not None and resp[0] == 0x50 and resp[1] == SESSION_DEFAULT

    def test_programming_session_dsc_returns_6_bytes(self):
        s = _sim()
        resp = _req(s, bytes([SID_DIAGNOSTIC_SESSION_CONTROL, SESSION_PROGRAMMING]))
        assert resp is not None and len(resp) == 6


# ===========================================================================
# TestMultiDIDReadByIdentifier
# ===========================================================================

class TestMultiDIDReadByIdentifier:
    """
    ISO 14229-1 §11.2.3: 0x22 may request multiple DIDs in one PDU.
    The positive response (0x62) concatenates [did_hi, did_lo, data] for each.
    """

    def test_single_did_response_format(self):
        s = _sim()
        resp = _rdbi(s, DID_VIN)
        assert resp is not None and resp[0] == 0x62
        assert resp[1] == (DID_VIN >> 8) and resp[2] == (DID_VIN & 0xFF)
        assert len(resp) == 1 + 2 + 17, f"Expected {1+2+17} bytes, got {len(resp)}"

    def test_two_dids_in_one_request(self):
        s = _sim()
        resp = _rdbi(s, DID_VIN, DID_SERIAL)
        assert resp is not None and resp[0] == 0x62
        expected_len = 1 + (2 + 17) + (2 + 4)
        assert len(resp) == expected_len, \
            f"Two-DID response: expected {expected_len} bytes, got {len(resp)}"

    def test_three_dids_in_one_request(self):
        s = _sim()
        resp = _rdbi(s, DID_VIN, DID_SERIAL, DID_ENGINE_SPD)
        assert resp is not None and resp[0] == 0x62
        expected_len = 1 + (2 + 17) + (2 + 4) + (2 + 2)
        assert len(resp) == expected_len, \
            f"Three-DID response: expected {expected_len} bytes, got {len(resp)}"

    def test_did_bytes_echoed_in_request_order(self):
        s = _sim()
        resp = _rdbi(s, DID_SERIAL, DID_VIN)
        assert resp is not None and resp[0] == 0x62
        # First DID in response must be DID_SERIAL
        assert resp[1] == (DID_SERIAL >> 8) and resp[2] == (DID_SERIAL & 0xFF)
        # Second DID starts after 2+4 bytes for DID_SERIAL
        offset = 1 + 2 + 4
        assert resp[offset] == (DID_VIN >> 8) and resp[offset + 1] == (DID_VIN & 0xFF)

    def test_two_dids_payload_sizes_are_independent(self):
        s = _sim()
        resp_vin    = _rdbi(s, DID_VIN)
        resp_serial = _rdbi(s, DID_SERIAL)
        resp_both   = _rdbi(s, DID_VIN, DID_SERIAL)
        vin_payload    = len(resp_vin) - 3     # 1 SID + 2 DID bytes
        serial_payload = len(resp_serial) - 3
        both_len = len(resp_both)
        assert both_len == 1 + (2 + vin_payload) + (2 + serial_payload), \
            "Two-DID response length must equal sum of individual payloads plus 2 DID-echo bytes each"

    def test_unknown_did_in_batch_returns_nrc_immediately(self):
        """If any DID in the batch is unknown, return NRC 0x31 — no partial response."""
        s = _sim()
        resp = _rdbi(s, DID_VIN, 0xDEAD)
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_REQUEST_OUT_OF_RANGE

    def test_odd_byte_count_after_sid_returns_nrc_13(self):
        """0x22 + odd bytes after SID (e.g. one byte of a DID): NRC 0x13."""
        s = _sim()
        resp = _req(s, bytes([SID_READ_DATA_BY_ID, 0xF1]))  # half a DID
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_INCORRECT_MSG_LEN

    def test_five_dids_in_one_request(self):
        """Batch read of all 5 default-session DIDs must succeed."""
        s = _sim()
        resp = _rdbi(s, DID_VIN, DID_SERIAL, DID_ENGINE_SPD, DID_COOLANT)
        assert resp is not None and resp[0] == 0x62
        # 1 SID + 4*(2 DID bytes) + (17+4+2+1) data bytes
        expected_len = 1 + 4 * 2 + (17 + 4 + 2 + 1)
        assert len(resp) == expected_len

    def test_wdbi_followed_by_rdbi_reads_written_value(self):
        """Write then read-back round-trip through the inline DID store."""
        s = _sim()
        _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        payload = bytes(range(11))  # 11-byte pattern
        wdbi_pdu = bytes([SID_WRITE_DATA_BY_ID,
                          DID_SPARE_PART >> 8, DID_SPARE_PART & 0xFF]) + payload
        wr = _req(s, wdbi_pdu)
        assert wr is not None and wr[0] == 0x6E
        rd = _rdbi(s, DID_SPARE_PART)
        assert rd is not None and rd[0] == 0x62
        readback = bytes(rd[3:3 + 11])
        assert readback == payload, f"Read-back mismatch: {readback.hex()} != {payload.hex()}"

    def test_session_gated_did_blocked_in_lower_session(self):
        """DID_SPARE_PART has min_session=extended (ordinal 3); blocked in default (ordinal 1)."""
        s = _sim()
        resp = _rdbi(s, DID_SPARE_PART)
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION

    def test_session_gated_did_accessible_in_required_session(self):
        s = _sim()
        _session(s, SESSION_EXTENDED)
        resp = _rdbi(s, DID_SPARE_PART)
        assert resp is not None and resp[0] == 0x62


# ===========================================================================
# TestReadDTCPrecision
# ===========================================================================

class TestReadDTCPrecision:
    """
    Verify sub-function 0x01 and 0x02 response byte layout matches ISO 14229-1 §12.
    DTCs start with status 0x00 — set status bits directly on state.dtcs to exercise
    the mask-filtering and record-building logic.
    """

    def _activate_dtc(self, state, index, status=0x08):
        state.dtcs[index]['status'] = status

    def test_sub01_response_format_no_active_dtcs(self):
        """
        Sub 0x01 with mask 0xFF and all DTCs inactive:
        response must be [0x59, 0x01, mask, 0x01, 0x00, 0x00].
        """
        s = _sim()
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x01, 0xFF]))
        assert resp is not None and resp[0] == 0x59
        assert resp[1] == 0x01, "Sub-function byte must echo 0x01"
        assert resp[2] == 0xFF, "Mask byte must echo 0xFF"
        assert resp[3] == 0x01, "Format identifier byte must be 0x01"
        assert len(resp) == 6, f"Sub 0x01 response must be 6 bytes, got {len(resp)}"

    def test_sub01_count_is_zero_when_no_dtcs_match(self):
        s = _sim()
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x01, 0xFF]))
        count = (resp[4] << 8) | resp[5]
        assert count == 0, f"Expected 0 active DTCs, got {count}"

    def test_sub01_count_is_one_after_activating_one_dtc(self):
        s = _sim()
        self._activate_dtc(s, 0, 0x08)  # testFailed bit
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x01, 0xFF]))
        count = (resp[4] << 8) | resp[5]
        assert count == 1, f"Expected 1 active DTC, got {count}"

    def test_sub01_count_is_two_when_both_dtcs_active(self):
        s = _sim()
        self._activate_dtc(s, 0, 0x08)
        self._activate_dtc(s, 1, 0x08)
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x01, 0xFF]))
        count = (resp[4] << 8) | resp[5]
        assert count == 2, f"Expected 2 active DTCs, got {count}"

    def test_sub01_mask_zero_reports_zero_count(self):
        """Mask 0x00 never matches any status byte, so count must be 0."""
        s = _sim()
        self._activate_dtc(s, 0, 0x08)  # testFailed, but mask 0x00 won't match 0x08
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x01, 0x00]))
        count = (resp[4] << 8) | resp[5]
        assert count == 0, "Mask 0x00 must match no DTCs regardless of status"

    def test_sub02_response_header_with_no_active_dtcs(self):
        """Sub 0x02 with no matching DTCs: [0x59, 0x02, mask] — exactly 3 bytes."""
        s = _sim()
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x02, 0xFF]))
        assert resp is not None and resp[0] == 0x59
        assert resp[1] == 0x02
        assert resp[2] == 0xFF
        assert len(resp) == 3, f"Sub 0x02 with no DTCs must be 3 bytes, got {len(resp)}"

    def test_sub02_dtc_record_is_four_bytes(self):
        """Each DTC record appended to sub 0x02: [code_hi, code_mid, code_lo, status]."""
        s = _sim()
        self._activate_dtc(s, 0, 0x08)
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x02, 0xFF]))
        assert len(resp) == 3 + 4, f"Sub 0x02 with 1 DTC: expected 7 bytes, got {len(resp)}"

    def test_sub02_dtc_code_bytes_match_config(self):
        """DTC 0xC00100 must appear as bytes [0xC0, 0x01, 0x00] in the record."""
        s = _sim()
        self._activate_dtc(s, 0, 0x08)
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x02, 0xFF]))
        code_bytes = bytes(resp[3:6])
        expected = bytes([0xC0, 0x01, 0x00])
        assert code_bytes == expected, \
            f"DTC 0xC00100 code bytes: expected {expected.hex()}, got {code_bytes.hex()}"

    def test_sub02_status_byte_matches_what_was_set(self):
        """The 4th byte of each DTC record must be the exact status value."""
        s = _sim()
        status = 0x2F  # arbitrary non-zero
        self._activate_dtc(s, 1, status)
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x02, 0xFF]))
        assert resp[6] == status, \
            f"DTC status byte: expected 0x{status:02X}, got 0x{resp[6]:02X}"

    def test_sub02_two_dtcs_appended_in_order(self):
        """With 2 active DTCs, sub 0x02 response is 3 + 4 + 4 = 11 bytes."""
        s = _sim()
        self._activate_dtc(s, 0, 0x08)
        self._activate_dtc(s, 1, 0x10)
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0x02, 0xFF]))
        assert len(resp) == 3 + 4 + 4, f"Expected 11 bytes, got {len(resp)}"

    def test_invalid_sub_function_returns_nrc_12(self):
        s = _sim()
        resp = _req(s, bytes([SID_READ_DTC_INFO, 0xFF]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED


# ===========================================================================
# TestRoutineControlLifecycle
# ===========================================================================

class TestRoutineControlLifecycle:
    """
    Verify RoutineControl (0x31) protocol completeness:
    sub-function coverage, security gating, session requirements, lifecycle ordering.
    """

    def test_stop_unsupported_returns_nrc_12(self):
        """Routine 0xFF00 (SelfTest) supports [start, results] but NOT stop."""
        s = _sim()
        _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x02, 0xFF, 0x00]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SUB_FUNCTION_NOT_SUPPORTED, \
            f"Stop on unsupported routine: expected NRC 0x12, got 0x{resp[2]:02X}"

    def test_results_before_start_returns_nrc_22(self):
        """Requesting results (sub 0x03) before starting the routine → NRC 0x22."""
        s = _sim()
        _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x03, 0xFF, 0x00]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_CONDITIONS_NOT_CORRECT, \
            f"Results before start: expected NRC 0x22, got 0x{resp[2]:02X}"

    def test_results_after_start_succeeds(self):
        s = _sim()
        _session(s, SESSION_EXTENDED)
        start = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x00]))
        assert start is not None and start[0] == 0x71
        results = _req(s, bytes([SID_ROUTINE_CONTROL, 0x03, 0xFF, 0x00]))
        assert results is not None and results[0] == 0x71, \
            f"Results after start: expected 0x71, got {results!r}"

    def test_security_gated_routine_blocked_without_unlock(self):
        """Routine 0xFF01 (ResetToFactoryDefaults) requires security level 1."""
        s = _sim()
        _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x01]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SECURITY_ACCESS_DENIED, \
            f"Expected NRC 0x33 without unlock, got 0x{resp[2]:02X}"

    def test_security_gated_routine_allowed_after_unlock(self):
        s = _sim()
        _session(s, SESSION_EXTENDED)
        assert _do_cmac_unlock(s, level=1)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x01]))
        assert resp is not None and resp[0] == 0x71, \
            f"Expected 0x71 after L1 unlock, got {resp!r}"

    def test_programming_session_routine_start(self):
        """Routine 0xFF10 (EraseNVM) requires programming session + L1 unlock."""
        s = _sim()
        _session(s, SESSION_PROGRAMMING)
        assert _do_cmac_unlock(s, level=1)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x10]))
        assert resp is not None and resp[0] == 0x71, \
            f"0xFF10 in programming session: expected 0x71, got {resp!r}"

    def test_programming_session_routine_blocked_in_default(self):
        """Routine 0xFF10 blocked in default session (ordinal 1 < 2)."""
        s = _sim()
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x10]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_SERVICE_NOT_SUPPORTED_IN_SESSION

    def test_routine_positive_response_is_exactly_4_bytes(self):
        """0x71 response: [0x71, sub_fn, rid_hi, rid_lo] — no extra bytes."""
        s = _sim()
        _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x00]))
        assert resp is not None and resp[0] == 0x71
        assert len(resp) == 4, f"RoutineControl positive response must be 4 bytes, got {len(resp)}"

    def test_start_response_echoes_correct_sub_fn_and_rid(self):
        s = _sim()
        _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x00]))
        assert resp is not None and resp[1] == 0x01
        assert resp[2] == 0xFF and resp[3] == 0x00

    def test_unknown_routine_id_returns_nrc_31(self):
        s = _sim()
        _session(s, SESSION_EXTENDED)
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xAA, 0xBB]))
        assert resp is not None and resp[0] == SID_NEGATIVE_RESPONSE
        assert resp[2] == NRC_REQUEST_OUT_OF_RANGE

    def test_start_then_results_then_start_again(self):
        """Routine can be re-started; results remain available after repeated starts."""
        s = _sim()
        _session(s, SESSION_EXTENDED)
        _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x00]))  # first start
        _req(s, bytes([SID_ROUTINE_CONTROL, 0x03, 0xFF, 0x00]))  # results
        _req(s, bytes([SID_ROUTINE_CONTROL, 0x01, 0xFF, 0x00]))  # second start
        resp = _req(s, bytes([SID_ROUTINE_CONTROL, 0x03, 0xFF, 0x00]))  # results again
        assert resp is not None and resp[0] == 0x71, \
            "Results must be available after second start"
